// Recibe: { input_base64, output_base64, nombre_archivo, nota }
const body = $input.item.json.body || $input.item.json;

const inputBase64  = body.input_base64  || body.input;
const outputBase64 = body.output_base64 || body.output;
const nombreArchivo = body.nombre || body.nombre_archivo || 'ejemplo.xlsx';
const nota = body.nota || '';

if (!inputBase64)  throw new Error('Falta input_base64');
if (!outputBase64) throw new Error('Falta output_base64');

const cleanInput  = inputBase64.replace(/^data:[^;]+;base64,/, '');
const cleanOutput = outputBase64.replace(/^data:[^;]+;base64,/, '');

return [{
  json: { nombreArchivo, nota, cleanInput, cleanOutput }
}];

const XLSX = require('xlsx');
const { nombreArchivo, nota, cleanInput, cleanOutput } = $input.item.json;

// --- INPUT: convertir a texto plano para contexto de la IA ---
const bufInput = Buffer.from(cleanInput, 'base64');
const wbInput  = XLSX.read(bufInput, { type: 'buffer' });
const wsInput  = wbInput.Sheets[wbInput.SheetNames[0]];
const rowsInput = XLSX.utils.sheet_to_json(wsInput, { header: 1, defval: null });

const textoInput = rowsInput
  .filter(row => row.some(v => v !== null && v !== undefined && v !== ''))
  .map(row => {
    const headers = rowsInput[0];
    return row
      .map((v, i) => {
        const key = (headers && headers[i]) ? headers[i] : `col${i}`;
        return v !== null && v !== undefined && v !== '' ? `${key}: ${v}` : null;
      })
      .filter(Boolean)
      .join(' | ');
  })
  .filter(Boolean)
  .join('\n');

// --- OUTPUT: guardar tal cual como JSON, sin transformar ni filtrar columnas ---
// El xlsx de salida YA ES el formato final validado, solo se parsea a JSON
const bufOutput  = Buffer.from(cleanOutput, 'base64');
const wbOutput   = XLSX.read(bufOutput, { type: 'buffer' });
const wsOutput   = wbOutput.Sheets[wbOutput.SheetNames[0]];
const rowsOutput = XLSX.utils.sheet_to_json(wsOutput, { defval: null });

// Filtrar solo filas completamente vacías
const filasOutput = rowsOutput.filter(row =>
  Object.values(row).some(v => v !== null && v !== undefined && v !== '')
);

const outputJson = JSON.stringify(filasOutput);

// Truncar input si supera límite de Sheets (50.000 chars)
const inputTruncado = textoInput.substring(0, 40000);

return [{
  json: {
    nombreArchivo,
    nota,
    input_excel: inputTruncado,
    output_json: outputJson,
    cant_filas_input: rowsInput.length,
    cant_filas_output: filasOutput.length
  }
}];
